library;

// Dart imports:
import 'dart:async';

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:fimber/fimber.dart';
import 'package:flutter_hooks/flutter_hooks.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure_code.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/utils/snack_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_loading_indicator.dart';
import 'package:baseball_detector_flutter/views/routers/app_router.dart';

final _logger = FimberLog('handleOperation');

typedef OperationCallback<T> = Future<Result<Failure, T>> Function({
  required Future<Result<Failure, T>> operation,
  FutureOr<String?> Function(T)? onSucceeded,
  FutureOr<String?> Function(Failure)? onFailed,
  bool Function(Failure)? shouldSendErrorLog,
  bool loadingDialogIsVisible,
});

OperationCallback<T> useOperation<T>() {
  final context = useContext();

  return useCallback(({
    required Future<Result<Failure, T>> operation,
    FutureOr<String?> Function(T)? onSucceeded,
    FutureOr<String?> Function(Failure)? onFailed,
    bool Function(Failure)? shouldSendErrorLog,
    bool loadingDialogIsVisible = true,
  }) async {
    final methodFc = failureCodeBuilder.category('VHO').category('HO');

    Route? dialog;
    if (loadingDialogIsVisible) {
      dialog = showLoadingDialog(context: context, visible: true);
    }

    Result<Failure, T> res;
    try {
      res = await operation;
    } catch (e, stackTrace) {
      // Except for operation result, unexpected exceptions are thrown.
      // ex) null reference, type cast error, etc.
      res = Left(Failure.undefined(
        code: methodFc.position('001'),
        stackTrace: stackTrace,
      ));
    } finally {
      // Always try to close the dialog
      if (dialog != null) {
        // Try to close dialog even if context is unmounted
        // This is important for team switching where widget tree gets rebuilt
        if (context.mounted) {
          await popLoadingDialog(context: context, dialog: dialog);
        } else {
          // Context is unmounted but dialog might still be visible
          // Use the global navigator key to close the dialog

          // Check if dialog is still active and try to close it using the global navigator
          if (dialog.isActive && appRouterKey.currentState != null) {
            if (dialog.isCurrent) {
              appRouterKey.currentState!.pop();
            }
          }
        }
      }
    }

    if (res.hasLeft) {
      String? message;
      if (onFailed != null) {
        message = await onFailed(res.left);
        if (message != null && context.mounted) {
          context.showErrorSnackBar(message);
        }
      }
      final sendErrorLog = shouldSendErrorLog?.call(res.left) ?? true;
      if (sendErrorLog) {
        _logger.e(
          res.left.translate(null),
          ex: res.left,
          stacktrace: res.left.stackTrace,
        );
      }
      return res;
    }

    if (onSucceeded != null) {
      final message = await onSucceeded(res.right);
      if (message != null && context.mounted) {
        context.showSuccessSnackBar(message);
        _logger.i('success: $message');
      }
    }

    return res;
  });
}

