// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/pitch_type_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/ball.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/pitch_type.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
import 'package:baseball_detector_flutter/utils/snack_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_dropdown_menu.dart';
import 'package:baseball_detector_flutter/views/hooks/use_operation.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/pitch_type_badge.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_session_edit_access.dart';

class PitchTypeDropdownButton extends HookConsumerWidget {
  const PitchTypeDropdownButton({
    required this.session,
    required this.ball,
    required this.onEditPitchType,
    this.overlayOffsetY,
    this.isDense = false,
    super.key,
  });

  final Session session;
  final Ball ball;
  final Future<Result<Failure, void>> Function(int ballId, String? pitchTypeId)
      onEditPitchType;
  final bool isDense;
  final double? overlayOffsetY;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final pitchTypeListState = ref.watch(pitchTypeListControllerProvider);
    final handleOperation = useOperation();
    final overlayWidth = context.isLandscape ? 200.0 : 160.0;
    final checkSessionEditAccess = useSessionEditAccess();

    return pitchTypeListState.fold(
      data: (pitchTypeList) {
        // pitchTypeList cannot be sorted.
        final sortedList = pitchTypeList.toList();
        sortedList.sort((a, b) => a.priority!.compareTo(b.priority!));

        return CustomDropdownMenu<PitchType>(
          value: ball.pitchType ?? sortedList[0],
          itemList: sortedList,
          overlayWidth: overlayWidth,
          maxHeight: context.screenHeight * 0.4,
          overlayOffsetY: overlayOffsetY,
          onChanged: (PitchType? newValue) async {
            if (newValue?.id == ball.pitchType?.id) {
              return;
            }

            final userId = ref.read(profileStorageProvider).getUserId();
            final isAccessible = await checkSessionEditAccess(session, userId!);
            if (!isAccessible) return;

            // Check if widget is still mounted after async operation
            if (!context.mounted) return;

            handleOperation(
              operation: onEditPitchType(ball.id!, newValue?.id),
              onSucceeded: (data) =>
                  context.l10n.analysis_result__change_pitch_type_succeeded,
              onFailed: (error) =>
                  '${context.l10n.analysis_result__change_pitch_type_failed}: ${error.translate(context.l10n)}',
              loadingDialogIsVisible: false,
            );
          },
          decoration: InputDecoration(
            border: const UnderlineInputBorder(
              borderSide: BorderSide.none,
            ),
            isDense: isDense,
            contentPadding: const EdgeInsets.all(0),
          ),
          itemBuilder: (pitchType) => PitchTypeBadge(
            pitchType: pitchType,
            emptyBadgeWhenNull: true,
            showDropdownIndicator: false,
          ),
          selectedItemBuilder: (pitchType) => PitchTypeBadge(
            pitchType: pitchType,
            emptyBadgeWhenNull: true,
            showDropdownIndicator: true,
          ),
        );
      },
      loading: () => const SizedBox.shrink(),
      error: (error) {
        WidgetsBinding.instance.addPostFrameCallback((_) {
          context.showErrorSnackBar(error.translate(context.l10n));
        });
        return const SizedBox.shrink();
      },
    );
  }
}
